void main();

void start_trap() {
    while (1)
        ;
}

__attribute__((aligned(16))) char stack0[KSTACKSIZE];

void start(long hartid, uint64 _dtb_entry) {

    // opensbi会将hartid放置在a0寄存器，而设备树的地址放置在a1寄存器，分别对应start函数的第一个和第二个参数
    extern uint64 dtb_entry;
    if (dtb_entry == 0) {
        dtb_entry = _dtb_entry;
    }

    //禁用分页
    w_satp(0);

    //开启外设中断和计时器中断，没有开启软件中断
    w_sie(r_sie() | SIE_SEIE | SIE_STIE);

    // 在每个CPU的tp寄存器中保存hartid
    w_tp(hartid);
    w_stvec((uint64)start_trap);

    main();
}

