proclist_t used_procs;

// 获取当前进程的指针
proc_t *myproc() {
    push_off();
    cpu_t *c = mycpu();
    proc_t *p = c->running_thread->td_proc;
    pop_off();
    return p;
}

spinlock_t pid_lock;
// 分配pid
static inline uint64_t pid_alloc(proc_t *p) {
    static uint64_t cnt = 0;
    acquire_spinlock(&pid_lock);
    cnt += 1;
    uint64_t new_pid = GENERATE_PID(cnt, p - procs);
    release_spinlock(&pid_lock);
    return new_pid;
}

// 分配一个新的进程
// 该进程需要有一个页表，页表中需要Trapframe和Trampoline
proc_t *proc_alloc() {
    acquire_spinlock(&free_procs.lock);
    if (LIST_EMPTY(&free_procs.list)) {
        release_spinlock(&free_procs.lock);
        // error("No free process.\n");
        return NULL;
    }

    proc_t *p = LIST_FIRST(&free_procs.list);
    LIST_REMOVE(p, p_list);
    release_spinlock(&free_procs.lock);

    p->p_status = USED;
    p->p_pid = pid_alloc(p);
    memset(&p->PCB_INIT_FIELD_START, 0, range_of(proc_t, PCB_INIT_FIELD_START, PCB_INIT_FIELD_END));

    p->p_parent = NULL;

    // acquire_spinlock(&used_procs.lock);
    // LIST_INSERT_HEAD(&used_procs.list, p, p_list);
    // release_spinlock(&used_procs.lock);

    proc_init_upt(p);

    return p;
}

// 分配并初始化一个用户空间页表
// 映射trampoline和trapframe
void proc_init_upt(proc_t *p) {
    // 1. 分配页表
    uint64_t upt = kvm_alloc();
    p->p_pt = (uint64_t *)upt;

    // 2. 映射trampoline
    extern char trampoline[];
    panic_on(page_map(p->p_pt, TRAMPOLINE, (uint64_t)trampoline, PTE_R | PTE_X | PTE_G));

    // TODO: signal
    // extern char trampoline[], user_sig_return[];
    // panic_on(page_map(p->p_pt, TRAMPOLINE, (uint64_t)trampoline, PTE_R | PTE_X | PTE_G));
    // panic_on(page_map(p->p_pt, SIGNAL_TRAMPOLINE, (uint64_t)user_sig_return, PTE_R | PTE_X | PTE_U));

    // 3. 映射trapframe
    p->p_trapframe = (trapframe_t *)vm_alloc();
    panic_on(page_map(p->p_pt, TRAPFRAME, (uint64_t)p->p_trapframe, PTE_R | PTE_W));
}

void proc_init_uvm(proc_t *proc, thread_t *init_td, const char *name, const void *bin, size_t size) {
    // 1. 初始化用户地址空间
    proc_init_ustack(proc, init_td);

    // 2. 加载代码段
    proc_init_ucode(bin, size, proc, init_td);

    // 3. 初始化用户线程信息
    assert(strlen(name) <= MAXPATH);
    strncpy(init_td->td_name, name, sizeof(init_td->td_name) - 1);
}

void proc_init_ustack(proc_t *proc, thread_t *init_td) {
    // 1. 初始化用户空间
    for (int i = 0; i < USTACK_INIT_PAGE_NUM; ++i) {
        uint64_t pa = vm_alloc();
        uint64_t va = USTACK_INIT_BOTTOM + i * PAGE_SIZE;
        panic_on(page_map(proc->p_pt, va, pa, PTE_R | PTE_W | PTE_U));
    }

    // 2. 分配可拓展的用户栈
    for (int i = 0; i < USTACK_EXTEND_PAGE_NUM; ++i) {
        uint64_t va = USTACK_BOTTOM + i * PAGE_SIZE;
        // 这里不需要分配物理页，只需要映射即可
        // 缺页中断时再分配物理页（大概）
        panic_on(page_map(proc->p_pt, va, 0, PTE_R | PTE_W | PTE_U));
    }

    // 3. 设置用户栈指针
    init_td->td_trapframe.sp = USTACKTOP;
    proc->p_brk = 0;
}

// 创建一个新的进程
void proc_create(const char *name, const void *bin, size_t size) {
    // 1. 分配一个进程和线程
    proc_t *p = proc_alloc();
    thread_t *t = thread_alloc();

    // 2. 将线程添加到进程的线程队列中
    proc_add_thread(p, t);

    // 3. 初始化用户空间
    proc_init_uvm(p, t, name, bin, size);

    // 4. 初始化文件系统
    init_proc_fs(&p->p_fs);

    // 5. 设置初始化线程
    t->td_status = RUNNABLE;

    // 6. 将线程加入调度队列
    acquire_spinlock(&run_threads.lock);
    TAILQ_INSERT_TAIL(&run_threads.tq, t, td_runq);
    release_spinlock(&run_threads.lock);
}

void proc_add_thread(proc_t *p, thread_t *t) {
    t->td_proc = p;
    TAILQ_INSERT_HEAD(&p->p_threads, t, td_plist);
}

// 释放一个进程
void proc_free(proc_t *p) {
    p->p_status = UNUSED;
    p->p_pid = 0;
    p->p_parent = NULL;

    acquire_spinlock(&free_procs.lock);
    LIST_INSERT_HEAD(&free_procs.list, p, p_list);
    release_spinlock(&free_procs.lock);
}

// 销毁一个进程
void proc_destroy(proc_t *p, int exitcode) {
    p->p_exitcode = exitcode;
    p->p_status = ZOMBIE;

    // 解引用全部用户页表
    vm_unmap(p->p_pt);
    p->p_pt = 0;
    p->p_brk = 0;

    // TODO: 回收fs资源
    // 结束信号

    // 递归回收子进程
    proc_t *child;
    LIST_UNTIL_EMPTY(child, &p->p_children) {
        LIST_REMOVE(child, p_sibling);
        if (child->p_status == ZOMBIE) {
            p->p_times.tms_cstime += child->p_times.tms_cstime;
            p->p_times.tms_cutime += child->p_times.tms_cutime;
            proc_free(child);
        } else {
            child->p_parent = &procs[PID_TO_INDEX(PID_INIT)];
        }
    }

    // 通知父进程
    if (p->p_pid != PID_INIT) {
        if (p->p_parent != NULL) {
            wakeup(p->p_parent);
        }
    }
}

// 初始化PCBs
void proc_init() {
    log(LEVEL_GLOBAL, "Process init start.\n");

    LIST_INIT(&free_procs.list);
    // LIST_INIT(&used_procs.list);

    for (int i = NPROC - 1; i >= 0; --i) {
        proc_t *p = &procs[i];
        LIST_INSERT_HEAD(&free_procs.list, p, p_list);
        TAILQ_INIT(&p->p_threads);
        LIST_INIT(&p->p_children);

        p->p_parent = NULL;
        p->p_pt = NULL;
        p->p_trapframe = NULL;
        p->p_brk = 0;
    }

    log(LEVEL_GLOBAL, "Process init done.\n");
}

