void proc_init_ucode(const void *bin, size_t size, proc_t *proc, thread_t *init_td) {
    load_code(bin, size, proc, init_td);
    uint64_t sp = init_td->td_trapframe.sp;
    sp -= sizeof(char **);
    sp -= sp % 16;
    // *(char ***)sp = NULL;
    sp -= sizeof(int);
    sp -= sp % 16;
    // *(int *)sp = 0;
    init_td->td_trapframe.sp = sp;
}

