void *kstacks;

spinlock_t tid_lock;

static uint64_t tid_alloc(thread_t *td) {
    static uint64_t cnt = 1;
    acquire_spinlock(&tid_lock);
    cnt += 1;
    uint64_t tid = GENERATE_TID(cnt, td - threads);
    release_spinlock(&tid_lock);
    return tid;
}

thread_t *thread_alloc() {
    acquire_spinlock(&free_threads.lock);
    if (TAILQ_EMPTY(&free_threads.tq)) {
        release_spinlock(&free_threads.lock);
        // error("No free thread.\n");
        return NULL;
    }

    thread_t *t = TAILQ_FIRST(&free_threads.tq);
    TAILQ_REMOVE(&free_threads.tq, t, td_freeq);
    release_spinlock(&free_threads.lock);

    t->td_tid = tid_alloc(t);
    t->td_status = USED;

    memset(&t->TCB_INIT_FIELD_START, 0, range_of(thread_t, TCB_INIT_FIELD_START, TCB_INIT_FIELD_END));

    t->td_context.ctx_ra = (uint64_t)utrap_sched;
    t->td_context.ctx_sp = KSTACK(get_td_index(t)) + KSTACKSIZE;

    return t;
}

// 回收传入僵尸进程的TCB，其余资源已被回收
// 进程调用exit或被kill后变为僵尸进程
void thread_free(thread_t *td) {
    td->td_status = UNUSED;
    td->td_proc = NULL;
    td->td_tid = 0;

    // 释放进程信号
    // TODO:

    acquire_spinlock(&free_threads.lock);
    TAILQ_INSERT_TAIL(&free_threads.tq, td, td_freeq);
    release_spinlock(&free_threads.lock);
}

// 释放线程资源
void thread_destroy(int exitcode) {
    thread_t *td = mythread();

    // log(888, "Thread %s exit with code %d\n", td->td_name, exitcode);

    proc_t *p = td->td_proc;
    int last_thread = 0;
    if (TAILQ_FIRST(&p->p_threads) == TAILQ_LAST(&p->p_threads, threadtq)) {
        last_thread = 1;
    }

    if (last_thread) {
        // 释放进程资源
        close_proc_fs(&p->p_fs);
        acquire_spinlock(&wait_lock);
        TAILQ_REMOVE(&p->p_threads, td, td_plist);
        proc_destroy(p, exitcode);
        release_spinlock(&wait_lock);
    } else {
        TAILQ_REMOVE(&p->p_threads, td, td_plist);
    }

    thread_free(td);
    schedule();
    panic("Should not reach here.\n");
}

void thread_init() {
    log(LEVEL_GLOBAL, "Thread init start.\n");

    // 初始化调度队列
    TAILQ_INIT(&free_threads.tq);
    TAILQ_INIT(&run_threads.tq);
    TAILQ_INIT(&sleep_threads.tq);

    for (int i = NTHREAD - 1; i >= 0; --i) {
        thread_t *t = &threads[i];
        t->td_status = UNUSED;

        // 插入空闲队列
        TAILQ_INSERT_HEAD(&free_threads.tq, t, td_freeq);

        // 线程锁
        // TODO: lock

        // 初始化内核栈
        t->td_kstack = (uint64_t)kstacks + KSTACKSIZE * i;

        // 将内核栈映射到内核页表
        extern pagetable_t kern_pagetable;
        for (int j = 0; j < 4; ++j) {
            uint64_t pa = t->td_kstack + j * PAGE_SIZE;
            uint64_t va = KSTACK(i) + j * PAGE_SIZE;
            panic_on(page_map(kern_pagetable, va, pa, PTE_R | PTE_W));
        }
    }

    log(LEVEL_GLOBAL, "Thread init done.\n");
}

