void schedule() {
    ctx_switch(&mythread()->td_context, 0);
}

//
void yield() {
    thread_t *td = mythread();
    td->td_status = RUNNABLE;
    schedule();
}

static thread_t *sched_next(thread_t *old_td) {
    acquire_spinlock(&run_threads.lock);
    if (old_td) {
        // 如果旧线程仍然可以运行，将其放回队列
        if (old_td->td_status == RUNNABLE) {
            TAILQ_INSERT_TAIL(&run_threads.tq, old_td, td_runq);
        } else if (old_td->td_status == SLEEPING) {
            // printf("Thread %s is sleeping\n", old_td->td_name);
        }
    }

    // 这里应该是一个循环，直到找到一个可以运行的线程
    // TODO: 这边暂时忽略了锁的问题，实际上需要检测sleep_threads的锁
    while (TAILQ_EMPTY(&run_threads.tq)) {
        // 如果运行队列和睡眠队列都为空，那么就关机
        if (TAILQ_EMPTY(&sleep_threads.tq)) {
            release_spinlock(&run_threads.lock);
            cpu_halt(); // 关机
        }

        // 只有一个核的话确实没啥用
        release_spinlock(&run_threads.lock);
        cpu_idle();
        acquire_spinlock(&run_threads.lock);
    }

    thread_t *ret = TAILQ_FIRST(&run_threads.tq);
    TAILQ_REMOVE(&run_threads.tq, ret, td_runq);

    release_spinlock(&run_threads.lock);
    return ret;
}

void sched_init() {
    assert(intr_get() == 0);
    assert(mycpu()->noff == 0);

    // 当前cpu
    cpu_t *cpu = mycpu();
    log(888, "Hart %d start running\n", cpuid());

    // 选择第一个进程
    thread_t *td = sched_next(NULL);
    cpu->running_thread = td;
    td->td_status = RUNNING;

    log(888, "Thread %s start running\n", td->td_name);
    ctx_enter(&td->td_context); // in switch.S
}

// 切换线程, 从当前线程切换到下一个线程
// 由switch.S调用
context_t *sched_switch(context_t *old_ctx, uint64_t param) {
    thread_t *old_td = container_of(old_ctx, thread_t, td_context);

    cpu_t *cpu = mycpu();
    cpu->running_thread = NULL;

    thread_t *td = sched_next(old_td);
    // log(888, "Hart %d switch from %s to %s\n", cpuid(), old_td->td_name, td->td_name);

    // 更新线程状态
    cpu->running_thread = td;
    td->td_status = RUNNING;
    return &td->td_context;
}

void sleep(void *chan, spinlock_t *lk, const char *msg) {
    thread_t *td = mythread();
    acquire_spinlock(&sleep_threads.lock);
    release_spinlock(lk);
    // TODO: 线程锁
    td->td_wchan = (uint64_t)chan;
    td->td_wmsg = msg;
    td->td_status = SLEEPING;
    TAILQ_INSERT_HEAD(&sleep_threads.tq, td, td_sleepq);
    release_spinlock(&sleep_threads.lock);

    // 进入睡眠
    schedule();

    // 唤醒至此
    td->td_wchan = 0;
    td->td_wmsg = NULL;

    // 释放进程锁

    acquire_spinlock(lk);
}

void wakeup(void *chan) {
    thread_t *td = NULL;
    threadtq_t readytq;
    TAILQ_INIT(&readytq.tq);

    acquire_spinlock(&sleep_threads.lock);
    TAILQ_FOREACH(td, &sleep_threads.tq, td_sleepq) {
        // TODO：线程锁
        if (td->td_wchan == (uint64_t)chan) {
            td->td_status = RUNNABLE;
            TAILQ_REMOVE(&sleep_threads.tq, td, td_sleepq);
            TAILQ_INSERT_TAIL(&readytq.tq, td, td_runq);
        }
    }

    // 防止丢失唤醒的进程，先获取就绪队列锁，再获取睡眠队列锁
    acquire_spinlock(&run_threads.lock);
    release_spinlock(&sleep_threads.lock);

    // 将线程放入运行队列
    TAILQ_CONCAT(&run_threads.tq, &readytq.tq, td_runq);
    release_spinlock(&run_threads.lock);
}

void wakeup_thread(thread_t *td) {
    // TODO: 线程锁
    if (td->td_status != SLEEPING) {
        return;
    }

    acquire_spinlock(&sleep_threads.lock);
    td->td_status = RUNNABLE;
    TAILQ_REMOVE(&sleep_threads.tq, td, td_sleepq);

    release_spinlock(&sleep_threads.lock);
    acquire_spinlock(&run_threads.lock);
    TAILQ_INSERT_TAIL(&run_threads.tq, td, td_runq);
    release_spinlock(&run_threads.lock);
}

tsevent_t tsevents[NTSEVENTS];
tseventq_t free_tsevents;
tseventq_t used_tsevents;

void tsleep_init() {
    TAILQ_INIT(&free_tsevents.tq);
    TAILQ_INIT(&used_tsevents.tq);

    for (int i = NTSEVENTS - 1; i >= 0; --i) {
        tsevent_t *tse = &tsevents[i];
        tse->tse_wchan = NULL;
        tse->tse_td = NULL;
        tse->tse_wakeus = 0;
        TAILQ_INSERT_HEAD(&free_tsevents.tq, tse, tse_freeq);
    }
}

static void tse_set_unused(tsevent_t *tse, int is_timeout) {
    assert(holding_spinlock(&used_tsevents.lock));
    TAILQ_REMOVE(&used_tsevents.tq, tse, tse_usedq);
    tse->tse_wchan = is_timeout ? (void *)-1 : NULL;
}

static tsevent_t *tse_alloc(thread_t *td, void *chan, uint64_t wakeus) {
    acquire_spinlock(&free_tsevents.lock);
    assert(!TAILQ_EMPTY(&free_tsevents.tq));
    tsevent_t *tse = TAILQ_FIRST(&free_tsevents.tq);
    TAILQ_REMOVE(&free_tsevents.tq, tse, tse_freeq);
    release_spinlock(&free_tsevents.lock);

    tse->tse_td = td;
    tse->tse_wchan = chan;
    tse->tse_wakeus = wakeus;

    acquire_spinlock(&used_tsevents.lock);
    if (wakeus) {
        tsevent_t *tmp = NULL;
        TAILQ_FOREACH(tmp, &used_tsevents.tq, tse_usedq) {
            if (tmp->tse_wakeus > wakeus || tmp->tse_wakeus == 0) {
                break;
            }
        }
        if (tmp) {
            TAILQ_INSERT_BEFORE(tmp, tse, tse_usedq);
        } else {
            TAILQ_INSERT_TAIL(&used_tsevents.tq, tse, tse_usedq);
        }
    } else {
        TAILQ_INSERT_TAIL(&used_tsevents.tq, tse, tse_usedq);
    }
    return tse;
}

static int tse_free(tsevent_t *tse) {
    int r = tse->tse_wchan == NULL ? 0 : -ETIMEDOUT;
    tse->tse_td = NULL;
    tse->tse_wchan = NULL;
    tse->tse_wakeus = 0;

    acquire_spinlock(&free_tsevents.lock);
    TAILQ_INSERT_HEAD(&free_tsevents.tq, tse, tse_freeq);
    release_spinlock(&free_tsevents.lock);

    return r;
}

int tsleep(void *chan, spinlock_t *lk, const char *msg, uint64_t wakeus) {
    tsevent_t *tse = tse_alloc(mythread(), chan, wakeus);
    if (lk) {
        release_spinlock(&used_tsevents.lock);
        sleep(chan, lk, msg);
        acquire_spinlock(&used_tsevents.lock);
    } else {
        sleep(chan, &used_tsevents.lock, msg);
    }
    int r = tse_free(tse);
    release_spinlock(&used_tsevents.lock);
    return r;
}

void tsleep_check() {
    acquire_spinlock(&used_tsevents.lock);
    uint64_t now = timer_mono_us();
    tsevent_t *tse = NULL;
    while ((tse = TAILQ_FIRST(&used_tsevents.tq))) {
        if (tse->tse_wakeus > now || tse->tse_wakeus == 0) {
            break;
        }
        void *chan = tse->tse_wchan;
        tse_set_unused(tse, 1);
        wakeup(chan);
    }
    release_spinlock(&used_tsevents.lock);
}

