static int duppage(PTE *pd, uint64_t target_va, PTE *target_pte) {
    PTE *child_pd = (PTE *)target_pte;
    if (page_lookup(child_pd, target_va) != 0) {
        // printf("duppage: target_va %lx already exists\n", target_va);
        return 0;
    }

    PTE parent_pte = page_lookup(pd, target_va);
    uint64_t perm = PTE_PERM(parent_pte);
    if ((!(parent_pte & PTE_V)) && (parent_pte & PTE_U)) {
        return page_map(child_pd, target_va, 0, perm);
    } else if ((perm & PTE_W) && (perm & PTE_U) && !(perm & PTE_SHARED)) {
        perm = (perm & ~PTE_W) | PTE_COW;
        return page_map(child_pd, target_va, PTE2PA(parent_pte), perm) ||
               page_map(pd, target_va, PTE2PA(parent_pte), perm);
    } else if (perm & PTE_U) {
        return page_map(child_pd, target_va, PTE2PA(parent_pte), perm);
    }

    error("duppage: unexpected permission %p\n", perm);
}

uint64_t thread_fork(thread_t *td, uint64_t childsp, uint64_t ptid, uint64_t tls, uint64_t ctid) {
    proc_t *proc = td->td_proc;
    thread_t *child_td = thread_alloc();

    proc_add_thread(proc, child_td);

    // 设置新线程的参数
    strncpy(child_td->td_name, td->td_name, MAX_PROC_NAME_LEN);
    child_td->td_status = RUNNABLE;

    // 复制父线程的用户现场
    child_td->td_trapframe = td->td_trapframe;
    // 子线程的栈顶
    if (childsp != 0) {
        child_td->td_trapframe.sp = childsp;
    }
    // 子线程的返回值
    child_td->td_trapframe.a0 = 0;
    child_td->td_trapframe.tp = tls;
    if (ptid != 0) {
        copy_out(ptid, (void *)&child_td->td_tid, sizeof(uint32_t));
    }
    child_td->td_ctid = ctid;

    acquire_spinlock(&run_threads.lock);
    TAILQ_INSERT_TAIL(&run_threads.tq, child_td, td_runq);
    release_spinlock(&run_threads.lock);

    return child_td->td_tid;
}

static int uvm_dup(pte_t *pd, pte_t *child_pd) {
    // 1. 页目录（1级页表）
    for (size_t i = 0; i < (1 << 9); ++i) {
        if (!(pd[i] & PTE_V)) {
            continue;
        }

        // 2. 2级页表
        pte_t *pt1 = (pte_t *)PTE2PA(pd[i]);
        for (size_t j = 0; j < (1 << 9); ++j) {
            if (!(pt1[j] & PTE_V)) {
                continue;
            }

            // 3. 页表项（3级页表）
            pte_t *pt2 = (pte_t *)PTE2PA(pt1[j]);
            for (size_t k = 0; k < (1 << 9); ++k) {
                if (pt2[k] == 0) {
                    continue;
                }

                uint64_t va = ((((i << 9) + j) << 9) + k) << 12;
                unwrap(duppage(pd, va, child_pd));
            }
        }
    }
    return 0;
}

uint64_t proc_fork(thread_t *td, uint64_t childsp, uint64_t flags) {
    proc_t *proc = td->td_proc;

    // 获取一个新进程和线程
    proc_t *child_proc = proc_alloc();
    thread_t *child_td = thread_alloc();

    proc_add_thread(child_proc, child_td);

    // 映射父进程的用户地址空间，引入写时复制
    // for (uint64_t va = 0; va < MAX_VA; va += PAGE_SIZE) {
    //     duppage(proc->p_pt, va, child_proc->p_pt);
    // }
    // 上面的实现有问题
    panic_on(uvm_dup(proc->p_pt, child_proc->p_pt));
    child_proc->p_brk = proc->p_brk;
    strcpy(child_td->td_name, td->td_name);
    strcat(child_td->td_name, "_child");
    fork_proc_fs(&proc->p_fs, &child_proc->p_fs);

    // TODO: signal

    child_td->td_status = RUNNABLE;

    // 创建父子进程间的父子关系
    child_proc->p_parent = proc;
    LIST_INSERT_HEAD(&proc->p_children, child_proc, p_sibling);
    // 复制父线程的用户现场
    child_td->td_trapframe = td->td_trapframe;
    // 子线程的栈顶
    if (childsp != 0) {
        child_td->td_trapframe.sp = childsp;
    }
    // 子线程的返回值
    child_td->td_trapframe.a0 = 0;

    acquire_spinlock(&run_threads.lock);
    TAILQ_INSERT_HEAD(&run_threads.tq, child_td, td_runq);
    release_spinlock(&run_threads.lock);
    return child_proc->p_pid;
}

