spinlock_t wait_lock;

extern int tmp_return_num;

static uint64_t wait_exit(thread_t *cur_td, proc_t *child_proc, uint64_t pstatus) {
    uint64_t pid = child_proc->p_pid;
    int32_t wstatus;

    if (pstatus) {
        wstatus = (child_proc->p_exitcode & 0xff) << 8;
        // printf("psatus: %lx, wstatus: %x\n", pstatus, wstatus);
        copy_out(pstatus, &wstatus, sizeof(int32_t));
        tmp_return_num = wstatus;
    }

    cur_td->td_proc->p_times.tms_cstime += child_proc->p_times.tms_cstime;
    cur_td->td_proc->p_times.tms_cutime += child_proc->p_times.tms_cutime;

    // 回收子进程
    LIST_REMOVE(child_proc, p_sibling);
    proc_free(child_proc);
    release_spinlock(&wait_lock);
    return pid;
}

static uint64_t wait_until_exit(thread_t *cur_td, proc_t *child_proc, uint64_t pstatus, int options) {
    // 若设置了WNOHANG，则直接返回
    if (options & WNOHANG) {
        release_spinlock(&wait_lock);
        return WAIT_NOHANG_EXIT;
    }
    while (child_proc->p_status != ZOMBIE) {
        sleep(cur_td->td_proc, &wait_lock, "waiting for child exit");
    }
    return wait_exit(cur_td, child_proc, pstatus);
}

uint64_t wait(thread_t *cur_td, int64_t pid, uint64_t pstatus, int options) {
    // log(LEVEL_GLOBAL, "wait: pid: %lx, pstatus: %lx, options: %x\n", pid, pstatus, options);

    assert(mycpu()->noff == 0);
    acquire_spinlock(&wait_lock);
    // 检查是否有能够等待的子进程
    if (LIST_EMPTY(&cur_td->td_proc->p_children)) {
        release_spinlock(&wait_lock);
        warn("no child proc.\n");
        return -1;
    }

    // 检查是否有指定的子进程
    while (1) {
        proc_t *child_proc = NULL;
        LIST_FOREACH(child_proc, &cur_td->td_proc->p_children, p_sibling) {
            if (pid != -1 && pid == child_proc->p_pid) {
                assert(child_proc->p_status != UNUSED);
                return wait_until_exit(cur_td, child_proc, pstatus, options);
            } else if (pid == -1 && child_proc->p_status == ZOMBIE) {
                return wait_exit(cur_td, child_proc, pstatus);
            }
        }
        // 若没有找到指定的子进程
        if (pid != -1) {
            release_spinlock(&wait_lock);
            return -1;
        }
        // 若设置了WNOHANG，则直接返回
        if (options & WNOHANG) {
            release_spinlock(&wait_lock);
            return WAIT_NOHANG_EXIT;
        }
        // 若没有指定子进程，且没有设置WNOHANG，则等待
        sleep(cur_td->td_proc, &wait_lock, "waiting for child to exit");
    }

    panic("should not reach here.\n");
}

