uint64_t intr_count[INTR_MAXNO + 1];

/*********** handle device interrupt ***********/
// 设备中断
void handle_device() {
    int irq = plic_claim();

    if (irq != INTERRUPT_TIMER) {
        uint64_t *addr = &intr_count[irq];
        __sync_add_and_fetch(addr, 1); // 原子操作
    }

    if (irq == VIRTIO0_IRQ) {
        // handle virtio0 interrupt
        virtio_intr();
    } else if (irq) {
        printf("unexpected device interrupt: %d\n", irq);
    }

    if (irq) {
        plic_complete(irq);
    }
}

/*********** handle page fault ***********/
// 写时复制
static int handle_cow(pte_t *pd, pte_t pte, uint64_t va) {
    uint64_t new_pa = vm_alloc();
    uint64_t old_pa = PTE2PA(pte);
    memcpy((void *)new_pa, (void *)old_pa, PAGE_SIZE);
    uint64_t new_perm = (PTE_PERM(pte) & ~PTE_COW) | PTE_W;
    return page_map(pd, va, new_pa, new_perm);
}

// 被动调页
static int handle_passive(pte_t *pd, pte_t pte, uint64_t va) {
    assert(!(pte >> 10));
    uint64_t new_pa = vm_alloc();
    uint64_t perm = pte; // 保证了权限位以外为0
    warn("passive page fault: badva=%lx, pte=%lx, perm=%lx\n", va, pte, perm);
    return page_map(pd, va, new_pa, perm);
}

// 页异常
void handle_page_fault(pte_t *pd, uint64_t va, int write) {
    // thread_t *td = mythread();
    // pte_t *pd = td->td_proc->p_pt;
    // uint64_t va = r_stval() & ~(PAGE_SIZE - 1);

    pte_t pte = page_lookup(pd, va);
    if ((write) && (pte) && (pte & PTE_U) && !(pte & PTE_W) && (pte & PTE_COW)) {
        if (handle_cow(pd, pte, va) == 0) {
            return;
        }
    } else if (!(pte & PTE_V) && (pte & PTE_U)) {
        if (handle_passive(pd, pte, va) == 0) {
            return;
        }
    }

    // handle page fault failed
    // TODO: signal
    printf("unhandled page fault: va = %p, pte = %p\n", va, pte);
    sys_exit(-1);
}

/*********** handle timer interrupt ***********/
// 时钟中断
// 即设置下一次时钟中断的时间
void handle_timer() {
    uint64_t *addr = &intr_count[INTERRUPT_TIMER];
    __sync_add_and_fetch(addr, 1); // 原子操作
    SBI_SET_TIMER(timer_mono_clock() + TIMER_INTERVAL);

    tsleep_check();
}

