extern void kern_vec();
extern char trampoline[], utrap_vec[], user_ret[];

#define hart_tf_uva(hartid) (((trapframe_t *)TRAPFRAME) + (hartid))

#define entry_user_ret(tf, satp)                                                                                       \
    (((void (*)(trapframe_t *, uint64_t))(TRAMPOLINE + (user_ret - trampoline)))(tf, (satp)))

// 用户态异常入口
// 调用本函数之前已存储了用户态下的所有寄存器现场，
// 并已加载内核页表并切换到对应内核线程的内核栈。
void utrap_entry() {
    thread_t *td = mythread();
    td->td_trapframe = td->td_proc->p_trapframe[cpuid()];

    utime_end(td);

    uint64_t cause = r_scause();
    uint64_t exc_code = cause & SCAUSE_EXC_MASK;
    w_stvec((uint64)kern_vec);

    // log(LEVEL_GLOBAL, "user trap: cause: %d, code: %d\n", cause, exc_code);

    if (cause & SCAUSE_INT_MASK) {
        // 用户态中断
        if (exc_code == INTERRUPT_TIMER) {
            // handle timer interrupt
            handle_timer();
            yield();
        } else if (exc_code == INTERRUPT_EXTERNEL) {
            // handle device interrupt
            handle_device();
        } else {
            // handle other interrupt
            printf("unknown user interrupt: %d\n", exc_code);
        }
    } else {
        // 用户态异常
        if (exc_code == EXCCODE_SYSCALL) {
            // handle syscall
            do_syscall(&td->td_trapframe);
        } else if (exc_code == EXCCODE_LOAD_PAGE_FAULT || exc_code == EXCCODE_STORE_PAGE_FAULT) {
            // 页异常
            handle_page_fault(myproc()->p_pt, r_stval() & ~(PAGE_SIZE - 1), exc_code == EXCCODE_STORE_PAGE_FAULT);
        } else {
            // 其他情况，直接退出即可
            // sys_exit(-1);
            // TODO: not implemented yet
            printf("unhandled user exception: %d\n", exc_code);
            sys_exit(-1);
        }
        stime_end(td);
    }

    // 中断或异常处理完毕，返回用户态
    utrap_return();
}

// 用户态异常返回
void utrap_return() {
    assert(intr_get() == 0);

    thread_t *td = mythread();
    utime_start(td);

    // 将内核地址页表存入trapframe
    td->td_trapframe.kernel_satp = r_satp();

    // 将cpu的id存入trapframe
    td->td_trapframe.hartid = cpuid();

    // 将内核线程入口、内核栈地址存入trapframe
    td->td_trapframe.trap_handler = (uint64_t)utrap_entry;
    td->td_trapframe.kernel_sp = KSTACK(get_td_index(td)) + KSTACKSIZE;

    // 拷贝trapframe到用户态
    trapframe_t *hart_tf = &td->td_proc->p_trapframe[cpuid()];
    *hart_tf = td->td_trapframe;

    // 设置用户态中断处理函数
    uint64_t trampoline_user_vec = TRAMPOLINE + (utrap_vec - trampoline);
    w_stvec(trampoline_user_vec);

    // 开启中断，返回用户态
    uint64_t sstatus = r_sstatus();
    sstatus &= ~SSTATUS_SPP; // SPP = 0: 用户态
    sstatus |= SSTATUS_SPIE; // SPIE = 1: 允许中断
    w_sstatus(sstatus);

    // 设置用户态页表
    uint64_t usatp = MAKE_SATP(td->td_proc->p_pt);
    trapframe_t *tf_uva = ((trapframe_t *)TRAPFRAME) + cpuid();
    ((void (*)(trapframe_t *, uint64_t))(TRAMPOLINE + (user_ret - trampoline)))(tf_uva, (usatp));
}

int is_first_thread = 1;

void utrap_sched() {
    // log(LEVEL_GLOBAL, "User trap sched %s on hart %d\n", mythread()->td_name, cpuid());
    if (is_first_thread == 1) {
        fat_init();
        is_first_thread = 2;
        wakeup(&is_first_thread);
    }
    utrap_return();
}

