extern void kern_vec();

/**
 * @brief 内核态异常入口
 * @note 中断：处理中断（但内核一般会屏蔽中断，所以这个大概率不发生）
 * @note 异常：直接panic
 * @note 内核态中断直接返回即可，不需要切换页表，所以也不需要实现在trampoline中
 */
void kernel_trap() {
    uint64 scause = r_scause();
    uint64 type = (scause >> 63ul);
    uint64 excCode = (scause & ((1ul << 63) - 1));
    // printf("kernel trap: type: %d, code: %d\n", type, excCode);
    // log(LEVEL_GLOBAL, "kernel trap: type: %d, code: %d\n", type, excCode);

    // 中断
    if (type == SCAUSE_INTERRUPT) {
        if (excCode == INTERRUPT_TIMER) {
            // handle timer interrupt
            handle_timer();
            // TODO: itimer, signal
        } else if (excCode == INTERRUPT_EXTERNEL) {
            // handle device interrupt
            handle_device();
        } else {
            // handle other interrupt
            printf("unknown interrupt: %d\n", excCode);
        }
    } else {
        // 异常
        panic("unhandled exception: %d\n", excCode);
    }
}

void trap_init() {
    w_stvec((uint64)kern_vec);

    // TODO: 这一块要check一下
