extern pagetable_t kern_pagetable;

FileSystem fat_super;

void read_BPB() {
    Buffer *block0 = fat_super.read(FAT32_Disk, 0);
    if (block0 == NULL) {
        panic("FAT: Failed to read block 0");
    }
    if (strncmp(block0->data + 82, "FAT32", 5)) {
        panic("FAT: Not a FAT32 filesystem");
    }
    fat_super.fat_bpb.bytesPerSec = *(uint16 *)(block0->data + 11);
    fat_super.fat_bpb.secPerClus = *(uint8 *)(block0->data + 13);
    fat_super.fat_bpb.rsvdSecCnt = *(uint16 *)(block0->data + 14);
    fat_super.fat_bpb.numFATs = *(uint8 *)(block0->data + 16);
    fat_super.fat_bpb.totSec32 = *(uint32 *)(block0->data + 32);
    fat_super.fat_bpb.fatsz = *(uint32 *)(block0->data + 36);
    fat_super.fat_bpb.rootClus = *(uint32 *)(block0->data + 44);
    fat_super.fat_bpb.fsinfo = *(uint16 *)(block0->data + 48);
    if (block0->data[510] != 0x55 || block0->data[511] != 0xAA) {
        panic("FAT: Invalid END signature");
    }
    assert(BUFFER_SIZE == fat_super.fat_bpb.bytesPerSec);

    // reserved
    uint32 notADataBlockNo = fat_super.fat_bpb.rsvdSecCnt;
    // fat
    notADataBlockNo += fat_super.fat_bpb.numFATs * fat_super.fat_bpb.fatsz;
    // minus the offset so the root cluster will be the first cluster after the reserved and fat area
    fat_super.data_start_sec = notADataBlockNo - fat_super.fat_bpb.rootClus * fat_super.fat_bpb.secPerClus;
    fat_super.fat_group_size = (fat_super.fat_bpb.bytesPerSec / sizeof(uint32));
    fat_super.root_sector = fat_super.fat_bpb.rootClus * fat_super.fat_bpb.secPerClus;
    fat_super.bytesPerClus = fat_super.fat_bpb.secPerClus * fat_super.fat_bpb.bytesPerSec;
    printf("FAT: bytesPerSec: %d\n", fat_super.fat_bpb.bytesPerSec);
    printf("FAT: secPerClus: %d\n", fat_super.fat_bpb.secPerClus);
    printf("FAT: rsvdSecCnt: %d\n", fat_super.fat_bpb.rsvdSecCnt);
    printf("FAT: numFATs: %d\n", fat_super.fat_bpb.numFATs);
    printf("FAT: fatsz: %d\n", fat_super.fat_bpb.fatsz);
    printf("FAT: totSec32: %d\n", fat_super.fat_bpb.totSec32);
    printf("FAT: rootClus: %d\n", fat_super.fat_bpb.rootClus);
    bufRelease(block0);
}

void check_FAT() {
    uint32 blockno = fat_super.fat_bpb.rsvdSecCnt;
    printf("FAT: Reading FAT table from block %d\n", blockno);
    Buffer *block = fat_super.read(FAT32_Disk, blockno);
    assert(((uint32 *)block->data)[0] == 0x0ffffff8);
    printf("FAT: FAT table is valid\n");
    bufRelease(block);
}

// read a sector in fact, so the number of fats in a group is sizeof(sector) / sizeof(uint32) = 512 / 4 = 128
static inline Buffer *read_GroupFAT(int groupno) {
    Buffer *fatBlock = fat_super.read(FAT32_Disk, fat_super.fat_bpb.rsvdSecCnt + groupno);
    return fatBlock;
}

// read a sector in data segment, **sectorno starts from 0**
static inline Buffer *read_data_sector(int sectorno) {
    Buffer *dataBlock = fat_super.read(FAT32_Disk, fat_super.data_start_sec + sectorno);
    return dataBlock;
}

static inline int write_data_sector(int sectorno, int offset, char *msg, int len) {
    if (len > BUFFER_SIZE)
        return -1;
    fat_super.write(FAT32_Disk, fat_super.data_start_sec + sectorno, offset, msg, len);
    return 0;
}

void write_data_cluster(uint32 clusno, int offset, char *data, int len) {
    uint32 startSecno = 0;
    for (; startSecno < fat_super.fat_bpb.secPerClus; ++startSecno) {
        if (startSecno == offset / fat_super.fat_bpb.bytesPerSec)
            break;
    }
    offset = offset % fat_super.fat_bpb.bytesPerSec;
    write_data_sector(clusno * fat_super.fat_bpb.secPerClus + startSecno, offset, data, len);
    uint32 end = offset;
    while (end < len) {
        startSecno++;
        if (startSecno == fat_super.fat_bpb.secPerClus)
            return;
        uint32 amount = (len - end) > fat_super.fat_bpb.bytesPerSec ? fat_super.fat_bpb.bytesPerSec : (len - end);
        write_data_sector(clusno * fat_super.fat_bpb.secPerClus + startSecno, 0, data + end, amount);
        end += amount;
    }
}

void read_FSInfo() {
    Buffer *info_block = fat_super.read(FAT32_Disk, fat_super.fat_bpb.fsinfo);
    fat_super.fat_fsinfo.leadSig = *(uint32 *)(info_block->data + 0);
    fat_super.fat_fsinfo.structSig = *(uint32 *)(info_block->data + 484);
    fat_super.fat_fsinfo.free_count = *(uint32 *)(info_block->data + 488);
    fat_super.fat_fsinfo.next_free = *(uint32 *)(info_block->data + 492);
    fat_super.fat_fsinfo.trailsig = *(uint32 *)(info_block->data + 508);
    bufRelease(info_block);
    assert(fat_super.fat_fsinfo.leadSig == 0x41615252);
    assert(fat_super.fat_fsinfo.structSig == 0x61417272);
    assert(fat_super.fat_fsinfo.trailsig == 0xAA550000);
    // fsinfo block do not know free_count and next_free
    if (fat_super.fat_fsinfo.free_count == -1 || fat_super.fat_fsinfo.next_free == -1) {
        for (int i = 0; i < fat_super.fat_bpb.fatsz; ++i) {
            Buffer *block = read_GroupFAT(i);
            uint32 *fat = (uint32 *)block->data;
            for (int j = 0; j < BUFFER_SIZE / sizeof(uint32); ++j) {
                if (fat[j] == 0) {
                    fat_super.fat_fsinfo.next_free = i * (BUFFER_SIZE / sizeof(uint32)) + j;
                    fat_super.fat_fsinfo.free_count =
                        fat_super.fat_bpb.fatsz * (fat_super.fat_bpb.bytesPerSec / sizeof(uint32)) -
                        fat_super.fat_fsinfo.next_free;
                    printf("FAT Info: free_count: 0x%lx\n", fat_super.fat_fsinfo.free_count);
                    printf("FAT Info: next_free: 0x%lx\n", fat_super.fat_fsinfo.next_free);
                    return;
                }
            }
        }
    }
    printf("FAT Info: free_count: 0x%lx\n", fat_super.fat_fsinfo.free_count);
    printf("FAT Info: next_free: 0x%lx\n", fat_super.fat_fsinfo.next_free);
}

void init_rw_func() {
