    char tmp[BUFFER_SIZE];
    Buffer *testSector = read_data_sector(fat_super.root_sector);
    memcpy(tmp, testSector->data, BUFFER_SIZE);
    // write msg
    write_data_sector(fat_super.root_sector, 0, msg, len + 1);
    // read again
    testSector = read_data_sector(fat_super.root_sector);
    assert(strcmp(testSector->data, msg) == 0);
    // write back raw data
    write_data_sector(fat_super.root_sector, 0, tmp, BUFFER_SIZE);
