#include "fs/buffer.h"
#include "dev/virtio.h"
#include "lib/error.h"
#include "lib/printf.h"
#include "lib/string.h"

#define BCACHE_GROUP_NUM 1

LRUCache bufferCache[BCACHE_GROUP_NUM];

void bufInit() {
    Buffer *buf;
    for (int i = 0; i < BCACHE_GROUP_NUM; i++) {
        // Create linked list of buffers
        bufferCache[i].head.prev = &bufferCache[i].head;
        bufferCache[i].head.next = &bufferCache[i].head;
        for (buf = bufferCache[i].buffers; buf < bufferCache[i].buffers + N_BUFFERS; buf++) {
            buf->next = bufferCache[i].head.next;
            buf->prev = &bufferCache[i].head;
            bufferCache[i].head.next->prev = buf;
            bufferCache[i].head.next = buf;
        }
    }
}

static Buffer *bufAlloc(uint32 dev, uint64 blockno) {
    Buffer *buf;
    uint64 group = blockno & (BCACHE_GROUP_NUM - 1);

    for (buf = bufferCache[group].head.next; buf != &bufferCache[group].head; buf = buf->next) {
        if (buf->dev_type == dev && buf->block_no == blockno) {
            buf->ref_cnt++;
            return buf;
        }
    }

    for (buf = bufferCache[group].head.prev; buf != &bufferCache[group].head; buf = buf->prev) {
        if (buf->ref_cnt == 0) {
            if (buf->valid == 1 && buf->dirty == 1) {
                virtio_ReadWrite(buf, 1);
            }
            buf->dev_type = dev;
            buf->block_no = blockno;
            buf->valid = 0;
            buf->dirty = 0;
            buf->ref_cnt = 1;
            return buf;
        }
    }

    panic("bget: no buffers");
}

void bufRelease(Buffer *buf) {
    int group = buf->block_no & (BCACHE_GROUP_NUM - 1);
    buf->ref_cnt--;

    if (buf->ref_cnt == 0) {
        buf->next->prev = buf->prev;
        buf->prev->next = buf->next;
        buf->next = bufferCache[group].head.next;
        buf->prev = &bufferCache[group].head;
        bufferCache[group].head.next->prev = buf;
        bufferCache[group].head.next = buf;
    }
}

Buffer *bufRead(uint32 dev, uint64 blockno) {
    Buffer *buf = bufAlloc(dev, blockno);
    if (!buf->valid) {
        virtio_ReadWrite(buf, 0);
        buf->valid = 1;
    }
    return buf;
}

void bufWrite(Buffer *buf) {
    buf->dirty = 1;
    return;
}

Buffer *BlockRead(uint32 dev, uint64 blockno) {
    return bufRead(dev, blockno);
}

void BlockWrite(uint32 dev, uint64 blockno, int offset, char *msg, int len) {
    Buffer *buf = bufRead(dev, blockno);
    memcpy((void *)(buf->data + offset), msg, len);
    bufWrite(buf);
}

void BlockFlush(Buffer *buf) {
    return;
    if (!buf->valid) {
        panic("BufferFlush: buffer not valid");
    }
    virtio_ReadWrite(buf, 1);
    buf->dirty = 0;
}

