int fat_read(uint64_t target, int offset, char *buf, int len) {
    int r = read_file((Directory *)target, offset, buf, len);
    return r;
}

int fat_write(uint64_t target, int offset, char *buf, int len) {
    int r = write_file((Directory *)target, offset, buf, len);
    return r;
}

int console_read(uint64_t target, int offset, char *buf, int len) {
    int index = 0;
    while (index < len) {
        int r;
        while ((r = console_getc()) == 255) {
            yield();
        }
        buf[index] = r;
        index++;
    }
    return index;
}

int console_write(uint64_t target, int offset, char *buf, int len) {
    acquire_spinlock(&console_lock);
    int i = 0;
    if (len == 1 && buf[0] == '\0') {
        release_spinlock(&console_lock);
        return 0;
    }
    for (i = 0; i < len; i++) {
        console_putc(buf[i]);
    }
    release_spinlock(&console_lock);
    return i;
}

int pipe_read(uint64_t target, int offset, char *buf, int len) {
    Pipe *p = (Pipe *)target;
    acquire_spinlock(&p->lock);
    if (p->writePos == 0) {
        release_spinlock(&p->lock);
        buf[0] = 0;
        return 1;
    }
    // while(p->using) {
    //     sleep(p, &p->lock, "waiting for writing to pipe");
    // }
    p->using = 1;
    uint32 index = 0;
    if (p->readPos >= p->writePos) {
        p->using = 0;
        release_spinlock(&p->lock);
        return 0;
    }
    while (p->readPos < p->writePos && index < len) {
        buf[index] = ((char *)(p->buffer))[p->readPos % PAGE_SIZE];
        p->readPos++;
        index++;
    }
    p->using = 0;
    release_spinlock(&p->lock);
    return index;
}

int pipe_write(uint64_t target, int offset, char *buf, int len) {
    Pipe *p = (Pipe *)target;
    acquire_spinlock(&p->lock);
    // while(p->using) {
    //     sleep(p, &p->lock, "waiting for reading from pipe");
    // }
    p->using = 1;
    p->dirty = 1;
    uint32 index = 0;
    while (index < len) {
        ((char *)(p->buffer))[p->writePos % PAGE_SIZE] = buf[index];
        p->writePos++;
        index++;
    }
    p->using = 0;
    release_spinlock(&p->lock);
    return index;
}

void file_init() {
    memset(file_table, 0, sizeof(file_table));
    memset(mapped_files, 0, sizeof(mapped_files));
    int readfd = alloc_fd();
    int writefd = alloc_fd();
    int errorfd = alloc_fd();

    init_spinlock(&console_lock, "console_lock");

    file_table[readfd].read = console_read;
    file_table[writefd].write = console_write;
    file_table[errorfd].read = console_read;
    file_table[errorfd].write = console_write;
    file_table[readfd].mode = O_RDONLY;
    file_table[writefd].mode = O_WRONLY;
    file_table[errorfd].mode = O_RDWR;
}

int openat(int dirfd, char *pathname, int flags, int mode) {
    int fd = alloc_fd();
    if (fd < 0)
        return -1;
    File *file = &file_table[fd];
    if (dirfd == CWD_FD) {
        char tmp[MAX_PATH_LEN];
        char *cwd = myproc()->p_fs.cwd;
        strcpy(tmp, cwd);
        strcat(tmp, "/");
        if (pathname[0] == '.')
            strcat(tmp, pathname + 1);
        else
            strcat(tmp, pathname);
        int r = walk_path(tmp, 0, &file->fileEntry);
        if (r < 0 && !(flags & O_CREATE)) {
            file->ref--;
            return -1;
        }
        if (r < 0 && alloc_file(tmp, &file->fileEntry) < 0) {
            file->ref--;
            return -1;
        }
    } else {
        if (dirfd < 0 || dirfd >= MAX_FILE_NUM)
            return -1;
        File *dir = &file_table[dirfd];
        if (dir->ref == 0)
            return -1;
        int r = walk_path_at(dir->fileEntry, (char *)pathname, 0, &file->fileEntry);
        if (r < 0 && !(flags & O_CREATE)) {
            file->ref--;
            return -1;
        }
        if (r < 0 && alloc_file_at(dir->fileEntry, (char *)pathname, &file->fileEntry) < 0) {
            file->ref--;
            return -1;
        }
    }
    file->pipe = NULL;
    file->offset = 0;
    file->mode = flags;
    file->read = fat_read;
    file->write = fat_write;
    file->dev_type = FILE;
    return fd;
}

int read(int fd, char *buf, size_t len) {
    File *file = &file_table[fd];
    if (!(file->mode == O_RDONLY || file->mode & O_RDWR))
        return -1;
    if (file->ref == 0)
        return -1;
    int r = file->read((uint64_t)file->fileEntry, file->offset, buf, len);
    if (r < 0)
        return -1;
    file->offset += len;
    return r;
}

int write(int fd, char *buf, size_t len) {
    File *file = &file_table[fd];
    if (!(file->mode & O_WRONLY || file->mode & O_RDWR))
        return -1;
    if (file->ref == 0)
        return -1;

    int r = file->write((uint64_t)file->fileEntry, file->offset, buf, len);
    if (r < 0)
        return -1;
    file->offset += len;
    return r;
}

int close(int fd) {
    File *file = &file_table[fd];
    if (file->ref == 0)
        return -1;
    file->ref--;
    if (file->dev_type == PIPE) {
        file->pipe->ref--;
        if (file->pipe->ref == 0) {
            return free_pipe(file->pipe);
        }
    }
    return 0;
}

int dup(int fd) {
    File *file = &file_table[fd];
    if (file->ref == 0)
        return -1;
    int newfd = alloc_fd();
    if (newfd < 0)
        return -1;
    file_table[newfd].fileEntry = file->fileEntry;
    file_table[newfd].ref = 1;
    file_table[newfd].mode = file->mode;
    file_table[newfd].read = file->read;
    file_table[newfd].write = file->write;
    return newfd;
}

int dup3(int oldfd, int newfd) {
    File *file = &file_table[oldfd];
    if (file->ref == 0)
        return -1;
    if (newfd < 0 || newfd >= MAX_FILE_NUM)
        return -1;
    if (file_table[newfd].ref > 0)
        return -1;
    file_table[newfd].fileEntry = file->fileEntry;
    file_table[newfd].ref = 1;
    file_table[newfd].mode = file->mode;
    file_table[newfd].read = file->read;
    file_table[newfd].write = file->write;
    return newfd;
}

int get_dir(int fd, Directory **dir) {
    File *file = &file_table[fd];
    if (file->ref == 0)
        return -1;
    *dir = file->fileEntry;
    return 0;
}

