void do_syscall(trapframe_t *tf) {
    uint64_t sysno = tf->a7;
    sys_func_t *sys_func = &sys_table[sysno];
    thread_t *td = mythread();

    // log the syscall
    if (!(sys_func && sys_func->name)) {
        log(LEVEL_GLOBAL, "Hart %d, Thread %s, called '%s', epc = %lx\n", cpuid(), td->td_name, sys_func->name,
            tf->epc);
    }

    // ecall占用4个字节，所以需要加4
    tf->epc += 4;

    // 获取调用函数，最多6个参数
    uint64_t (*func)(uint64_t, uint64_t, uint64_t, uint64_t, uint64_t, uint64_t) = sys_func->func;
    if (!func) {
        tf->a0 = -1;
        return;
    }

    tf->a0 = func(tf->a0, tf->a1, tf->a2, tf->a3, tf->a4, tf->a5);
    panic_on(tf->a0 < 0);
}

