uint64_t sys_getpid() {
    return myproc()->p_pid;
}

uint64_t sys_getppid() {
    if (myproc()->p_parent == NULL) {
        return -1;
    }
    return myproc()->p_parent->p_pid;
}

int sys_sched_yield() {
    yield();
    return 0;
}

uint64_t sys_clone(uint64_t flags, uint64_t stack, uint64_t ptid, uint64_t tls, uint64_t ctid) {
    if (flags & CLONE_VM) {
        return thread_fork(mythread(), stack, ptid, tls, ctid);
    } else {
        return proc_fork(mythread(), stack, flags);
    }
}

void sys_exit(int code) {
    thread_destroy(code);
}

int tmp_return_num;

uint64_t sys_wait4(uint64_t pid, uint64_t status, uint64_t options) {
    int r = wait(mythread(), pid, status, options);
    if (status != 0)
        copy_out(status, &tmp_return_num, sizeof(int));
    return r;
    // return wait(mythread(), pid, status, options);
}

int sys_execve(uint64_t path, char **argv, uint64_t envp) {
    thread_t *td = mythread();
    proc_t *p = myproc();

    assert(TAILQ_FIRST(&p->p_threads) == TAILQ_LAST(&p->p_threads, threadtq_head));

    char path_buf[MAX_PROC_NAME_LEN];
    copy_in(path, path_buf, MAX_PROC_NAME_LEN);
    void *bin;
    size_t size;

    // 检查ELF头是否合法
    int64_t file_id = file_load(path_buf, &bin, &size);
    if (file_id < 0) {
        return (int)file_id;
    }
    if (!check_elf_format(bin, size)) {
        file_unload(file_id);
        return -ENOEXEC;
    }

    // printf("%lx %d\n", (uint64_t)bin, size);

    // 重置用户栈
    // for (size_t i = 0; i < USTACK_PAGE_NUM; ++i) {
    //     uint64_t stackva = USTACK_BOTTOM + i * PAGE_SIZE;
    //     pte_t pte = page_lookup(p->p_pt, stackva);
    //     panic_on(page_unmap(p->p_pt, stackva));
    //     uint64_t pa = PTE2PA(pte);
    //     uint64_t perm = PTE_PERM(pte);
    //     panic_on(page_map(p->p_pt, stackva, pa, perm));
    // }

    proc_t tempp = {.p_pt = (pte_t *)kvm_alloc()};
    thread_t temptd = {.td_proc = &tempp};
    proc_init_ustack(&tempp, &temptd);

    // 迁移新的用户栈到旧的页表
    for (int i = 0; i < USTACK_PAGE_NUM; i++) {
        uint64_t stackva = USTACK_BOTTOM + i * PAGE_SIZE;
        // 解引用并释放旧页表上已过时的栈
        panic_on(page_unmap(p->p_pt, stackva));
        // 将新页表上的栈映射到旧页表上
        pte_t pte = page_lookup(tempp.p_pt, stackva);
        uint64_t pa = PTE2PA(pte);
        uint64_t perm = PTE_PERM(pte);
        panic_on(page_map(p->p_pt, stackva, pa, perm));
    }
    // 回收临时页表
    vm_unmap(tempp.p_pt);

    td->td_trapframe.sp = USTACKTOP;

    // 回收原有的地址空间
    for (uint64_t va = 0; va < p->p_brk; va += PAGE_SIZE) {
        if (page_lookup(p->p_pt, va) & PTE_V) {
            // printf("unmap %lx\n", va);
            panic_on(page_unmap(p->p_pt, va));
        }
    }
    p->p_brk = 0;
    td->td_ctid = 0;

    // 加载新的地址空间和代码
    proc_init_ucode(bin, size, p, td);
    strcpy(td->td_name, path_buf);

    file_unload(file_id);

    // 刷新指令cache，防止数据不正常
    __asm__ __volatile__("fence.i" : : : "memory");

    return 0;
}

uint64_t sys_nanosleep(uint64_t time_spec) {
    timespec_t ts;
    copy_in(time_spec, &ts, sizeof(timespec_t));
    tsleep(&ts, NULL, "nanosleep", TS_USEC(ts) + timer_mono_us());
    return 0;
}

int64_t sys_times(uint64_t utimes) {
    times_t times = myproc()->p_times;
    copy_out(utimes, &times, sizeof(times_t));
    return timer_mono_clock();
}

