static int sys_map(uint64_t start, size_t len, uint64_t perm) {
    uint64_t from = PGROUNDDOWN(start);
    uint64_t to = PGROUNDUP(start + len - 1);
    pte_t *pd = myproc()->p_pt;
    for (uint64_t va = from; va < to; va += PAGE_SIZE) {
        pte_t pte = page_lookup(pd, va);
        if (PTE2PA(pte) == 0) {
            if (va < 0x2000000) {
                // 主动调页
                panic_on(page_map(pd, va, vm_alloc(), perm));
            } else {
                // 被动调页
                assert(perm & PTE_U);
                panic_on(page_map(pd, va, 0, perm));
            }
        }
    }
    return 0;
}

static int sys_unmap(uint64_t start, size_t len) {
    uint64_t from = PGROUNDUP(start);
    uint64_t to = PGROUNDDOWN(start + len - 1);
    pte_t *pd = myproc()->p_pt;
    for (uint64_t va = from; va < to; va += PAGE_SIZE) {
        panic_on(page_unmap(pd, va));
    }
    return 0;
}

static inline uint64_t get_perm_by_prot(int prot) {
    uint64_t perm = PTE_U;
    if (prot & PROT_EXEC) {
        perm |= PTE_X;
    }
    if (prot & PROT_READ) {
        perm |= PTE_R;
    }
    if (prot & PROT_WRITE) {
        perm |= PTE_W;
    }
    return perm;
}

// 修改数据段的大小；
// addr若为0，传回当前堆的位置；
// addr不为0时，将堆的位置设置为addr，返回新堆的位置
int sys_brk(uint64_t addr) {
    int ret;
    uint64_t cur_brk = myproc()->p_brk;
    if (addr == 0) {
        return cur_brk;
    } else if (addr < cur_brk) {
        // 收缩堆
        myproc()->p_brk = addr;
        ret = sys_unmap(addr + 1, cur_brk);
    } else {
        // 扩展堆
        myproc()->p_brk = addr;
        ret = sys_map(cur_brk, addr - cur_brk, PTE_R | PTE_W | PTE_U);
    }
    return ret < 0 ? ret : addr;
}

// 将文件或设备映射到内存中；
// 如果start == 0，则由内核指定虚拟地址
void *sys_mmap(uint64_t start, size_t len, int prot, int flags, int fd, int64_t off) {
    start = PGROUNDUP(start);
    len = PGROUNDUP(len);

    if (len == 0) {
        return MAP_FAILED;
    }

    // 当start为0时，由内核指定虚拟地址
    if (start == 0) {
        start = myproc_fs()->mmap_addr;
        uint64_t new_addr = PGROUNDUP(start + len);
        if (new_addr > MMAP_END) {
            return MAP_FAILED;
        }
        myproc_fs()->mmap_addr = new_addr;
    }

    // 指定权限位
    uint64_t perm = get_perm_by_prot(prot);

    // 在父子进程之间共享内存
    if (flags & MAP_SHARED) {
        perm |= PTE_SHARED;
    }

    if (flags & MAP_ANONYMOUS) {
        // 如果是匿名映射
        int ret = sys_map(start, len, perm);
        if (ret < 0) {
            return MAP_FAILED;
        }
        return (void *)start;
    } else {
        // 文件映射
        return file_map(myproc(), fd, start, len, perm, off);
    }

    return MAP_FAILED;
}
int sys_munmap(uint64_t start, size_t len) {
    return sys_unmap(start, len);
}

