int sys_uname(uint64_t upuname) {
    static utsname_t utsname = {.sysname = "Phoenix",
                                .nodename = "phoenix_riscv64_machine",
                                .release = "1.0",
                                .version = "1.0",
                                .machine = "riscv64"};
    copy_out(upuname, &utsname, sizeof(utsname_t));
    return 0;
}

int sys_gettimeofday(uint64_t uptv, uint64_t uptz) {
    int64_t clk_time = timer_rt_clock();
    timeval_t tv = {.tv_sec = CLOCK2SEC(clk_time), .tv_usec = CLOCK2USEC(clk_time)};
    timezone_t tz = {0, 0};

    if (uptv) {
        copy_out(uptv, &tv, sizeof(timeval_t));
    }
    if (uptz) {
        copy_out(uptz, &tz, sizeof(timezone_t));
    }
    return 0;
}
