int sys_openat(int fd, uint64 filename, int flags, int mode) {
    char kname[256] = {};
    copy_in_check_end(filename, kname, 256);
    return openat(fd, kname, flags, mode);
}

int sys_read(int fd, uint64_t buf, size_t len) {
    char kbuf[1024] = {};
    int r = read(fd, kbuf, len);
    if (r < 0) {
        return r;
    }
    copy_out(buf, kbuf, len);
    return r;
}

int sys_write(int fd, uint64_t buf, size_t len) {
    char kbuf[1024] = {};
    copy_in(buf, kbuf, len);
    return write(fd, kbuf, len);
}

